string longestHappyPrefix(string &s) {
    int n = s.length();
    if (n == 0) return "";

    // lps[i] will store the length of the longest prefix which is also a suffix 
    // for the substring s[0...i]
    vector<int> lps(n, 0);
    int len = 0; // length of the previous longest prefix suffix
    int i = 1;

    // Build the lps array
    while (i < n) {
        if (s[i] == s[len]) {
            len++;
            lps[i] = len;
            i++;
        } else {
            // This is tricky. Consider the example "ABCAAAAA"
            if (len != 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }

    // The length of the longest happy prefix for the whole string is at the last index
    int happyPrefixLength = lps[n - 1];

    return s.substr(0, happyPrefixLength);
}

code.Python3:
def longestHappyPrefix(s: str) -> str:
    n = len(s)
    if n == 0:
        return ""

    lps = [0] * n
    length = 0
    i = 1

    # Build the lps array
    while i < n:
        if s[i] == s[length]:
            length += 1
            lps[i] = length
            i += 1
        else:
            if length != 0:
                length = lps[length - 1]
            else:
                lps[i] = 0
                i += 1

    happyPrefixLength = lps[n - 1]
    return s[:happyPrefixLength]

code.C:
void longestHappyPrefix(const char* s, char* result) {
    int n = strlen(s);
    if (n == 0) {
        result[0] = '\0';
        return;
    }

    int* lps = (int*)calloc(n, sizeof(int));
    int len = 0;
    int i = 1;

    // Build the lps array
    while (i < n) {
        if (s[i] == s[len]) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if (len != 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }

    int happyPrefixLength = lps[n - 1];
    strncpy(result, s, happyPrefixLength);
    result[happyPrefixLength] = '\0';

    free(lps);
}

