function longestHappyPrefix(s) {
    if (!s || s.length === 0) return "";
    let n = s.length;

    let lps = new Int32Array(n);
    let len = 0;
    let i = 1;

    while (i < n) {
        if (s.charCodeAt(i) === s.charCodeAt(len)) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if (len !== 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }


    let happyPrefixLength = lps[n - 1];
    return happyPrefixLength > 0 ? s.substring(0, happyPrefixLength) : "";
